mapper.select:
select trace_id, min(create_time) as start_time, max(create_time) as end_time, max(session_id) as session_id, max(user_id) as user_id, case when bool_or(lower(status) = 'failed') then 'FAILED' when bool_or(lower(status) = 'running') then 'RUNNING' else 'SUCCESS' end as status, greatest( sum(coalesce(latency_ms, 0)), cast(round(extract(epoch from (max(create_time) - min(create_time))) * 1000) as bigint), 1 ) as duration_ms from t_qa_trace_log
and trace_id like #{traceIdPattern}
group by trace_id order by max(create_time) desc
